import{bQ as e,aL as d,u as a,G as o}from"./chunks/framework.D06dwy5q.js";const n=JSON.parse('{"title":"域名和 DNS","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/03-域名和DNS.md","filePath":"00.互联网与架构基础/03-域名和DNS.md","lastUpdated":null}'),c={name:"00.互联网与架构基础/03-域名和DNS.md"};function r(l,t,p,A,i,E){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="域名和-dns" tabindex="-1">域名和 DNS <a class="header-anchor" href="#域名和-dns" aria-label="Permalink to &quot;域名和 DNS&quot;">​</a></h1><p>网站最后要连到 IP 地址，但人很难记住一串数字。域名就是给 IP 起一个容易记的名字，DNS 负责把这个名字查回地址。</p><p>平时访问 <code>www.example.com</code>，浏览器不会凭空知道它在哪里。它要先问 DNS：这个名字对应哪个 IP。网站迁移、接入 CDN、切换机房、内网服务发现，很多事情都和 DNS 有关。</p><h2 id="一、域名长什么样" tabindex="-1">一、域名长什么样 <a class="header-anchor" href="#一、域名长什么样" aria-label="Permalink to &quot;一、域名长什么样&quot;">​</a></h2><p>域名从右往左看层级。<code>www.example.com</code> 里，<code>com</code> 是顶级域，<code>example.com</code> 是主域名，<code>www</code> 是这个主域名下面的一个名字。</p><p>常见命名：</p><table tabindex="0"><thead><tr><th>域名</th><th>常见用途</th></tr></thead><tbody><tr><td><code>www.example.com</code></td><td>网站首页</td></tr><tr><td><code>api.example.com</code></td><td>后端接口</td></tr><tr><td><code>static.example.com</code></td><td>静态资源</td></tr><tr><td><code>grafana.example.com</code></td><td>监控平台</td></tr><tr><td><code>harbor.example.com</code></td><td>镜像仓库</td></tr></tbody></table><p>一个主域名下面可以挂很多业务名。运维看到这些名字时，先分清它们分别指向哪个入口：有的是公网入口，有的是内网入口，有的是 CDN，有的是 Kubernetes Ingress。</p><h2 id="二、谁来回答域名" tabindex="-1">二、谁来回答域名 <a class="header-anchor" href="#二、谁来回答域名" aria-label="Permalink to &quot;二、谁来回答域名&quot;">​</a></h2><p>客户端一般不会自己从根 DNS 一路查到底。系统里配置的 DNS 服务器会帮它查询，这类服务器常叫递归 DNS。真正保存某个域名解析记录的地方，叫权威 DNS。</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20autonumber%0A%20%20participant%20Client%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20participant%20Recursor%20as%20%E9%80%92%E5%BD%92%20DNS%0A%20%20participant%20Root%20as%20%E6%A0%B9%20DNS%0A%20%20participant%20TLD%20as%20%E9%A1%B6%E7%BA%A7%E5%9F%9F%20DNS%0A%20%20participant%20Auth%20as%20%E6%9D%83%E5%A8%81%20DNS%0A%0A%20%20Client-%3E%3ERecursor%3A%20%E6%9F%A5%E8%AF%A2%20www.example.com%0A%20%20Recursor-%3E%3ERoot%3A%20%E6%9F%A5%E8%AF%A2%20.com%20%E5%9C%A8%E5%93%AA%E9%87%8C%0A%20%20Root--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%20.com%20DNS%0A%20%20Recursor-%3E%3ETLD%3A%20%E6%9F%A5%E8%AF%A2%20example.com%20%E5%9C%A8%E5%93%AA%E9%87%8C%0A%20%20TLD--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%E6%9D%83%E5%A8%81%20DNS%0A%20%20Recursor-%3E%3EAuth%3A%20%E6%9F%A5%E8%AF%A2%20www.example.com%0A%20%20Auth--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%20A%20%2F%20CNAME%20%E8%AE%B0%E5%BD%95%0A%20%20Recursor--%3E%3EClient%3A%20%E8%BF%94%E5%9B%9E%E8%A7%A3%E6%9E%90%E7%BB%93%E6%9E%9C%0A"></div><p>日常看到的 <code>8.8.8.8</code>、<code>114.114.114.114</code>、运营商 DNS、公司内网 DNS，多数是递归 DNS。域名托管平台里配置的解析记录，最终由权威 DNS 对外回答。</p><h2 id="三、解析记录" tabindex="-1">三、解析记录 <a class="header-anchor" href="#三、解析记录" aria-label="Permalink to &quot;三、解析记录&quot;">​</a></h2><p>DNS 记录不是只有 IP。不同记录做不同事情。</p><table tabindex="0"><thead><tr><th>类型</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><code>A</code></td><td>域名指向 IPv4</td><td><code>www -&gt; 203.0.113.10</code></td></tr><tr><td><code>AAAA</code></td><td>域名指向 IPv6</td><td><code>www -&gt; 2001:db8::10</code></td></tr><tr><td><code>CNAME</code></td><td>域名指向另一个域名</td><td><code>www -&gt; cdn.example.net</code></td></tr><tr><td><code>MX</code></td><td>邮件服务器</td><td><code>example.com -&gt; mail.example.com</code></td></tr><tr><td><code>TXT</code></td><td>文本验证、SPF、DKIM 等</td><td><code>v=spf1 ...</code></td></tr><tr><td><code>NS</code></td><td>指定权威 DNS</td><td><code>example.com -&gt; ns1.example.net</code></td></tr></tbody></table><p>网站入口最常见的是 A、AAAA 和 CNAME。接 CDN 时，业务域名常 CNAME 到 CDN 分配的域名，再由 CDN 返回边缘节点 IP。</p><h2 id="四、ttl-和缓存" tabindex="-1">四、TTL 和缓存 <a class="header-anchor" href="#四、ttl-和缓存" aria-label="Permalink to &quot;四、TTL 和缓存&quot;">​</a></h2><p>DNS 查询结果会被缓存一段时间。TTL 就是缓存时间。</p><p>TTL 写 300，表示结果可以缓存 300 秒。TTL 写得长，查询少，切换慢；TTL 写得短，切换快一些，查询会多一些。</p><p>域名迁移前，经常会把 TTL 调低。比如原来是 3600 秒，先改成 300 秒，等旧缓存逐渐过期后再改 A 记录。这样切错了也能更快回到旧地址。</p><p>已经被缓存的旧结果不会因为修改解析记录立刻消失。某些浏览器、操作系统、运营商 DNS 还会有自己的缓存，所以“解析已经改了，但还有人访问旧 IP”在迁移时很常见。</p><h2 id="五、内网名字" tabindex="-1">五、内网名字 <a class="header-anchor" href="#五、内网名字" aria-label="Permalink to &quot;五、内网名字&quot;">​</a></h2><p>DNS 不只用于公网。公司内部、云 VPC、Kubernetes 集群里也会用自己的域名。</p><table tabindex="0"><thead><tr><th>场景</th><th>常见名字</th></tr></thead><tbody><tr><td>公司内部平台</td><td><code>gitlab.company.local</code></td></tr><tr><td>云 VPC 内服务</td><td><code>mysql.internal.example.com</code></td></tr><tr><td>Kubernetes Service</td><td><code>api.default.svc.cluster.local</code></td></tr></tbody></table><p>内网域名让服务不用写死 IP。数据库切主、Pod 重建、服务扩容以后，IP 可能变化，名字可以保持不变。</p><p>Kubernetes 里访问 <code>api.default.svc.cluster.local</code>，本质也是 DNS 查询。Service 名或 namespace 写错时，应用日志里可能出现 <code>lookup api.default.svc.cluster.local: no such host</code>。如果 Service 存在但后端 Pod 没有就绪，DNS 可能解析成功，实际请求会卡在 Service 或 Endpoints 这一层。</p><h2 id="六、常见解析异常" tabindex="-1">六、常见解析异常 <a class="header-anchor" href="#六、常见解析异常" aria-label="Permalink to &quot;六、常见解析异常&quot;">​</a></h2><p>DNS 问题不要只看“能不能解析”，还要看解析出了什么。</p><table tabindex="0"><thead><tr><th>结果</th><th>常见含义</th></tr></thead><tbody><tr><td><code>NXDOMAIN</code></td><td>域名不存在，或者没有对应记录</td></tr><tr><td><code>SERVFAIL</code></td><td>DNS 服务器处理失败，上游或权威 DNS 可能异常</td></tr><tr><td>解析到旧 IP</td><td>缓存还没过期，或者某处写了固定 hosts</td></tr><tr><td>不同地区结果不同</td><td>CDN、智能解析、运营商缓存差异</td></tr></tbody></table><p><code>NXDOMAIN</code> 不一定就是故障。有些应用会主动尝试多个候选域名，某些候选域名不存在也会打出 NXDOMAIN。多个核心域名同时 <code>SERVFAIL</code>，或者解析耗时突然从几毫秒涨到几秒，更像是 DNS 链路出了问题。</p><p>DNS 是访问链路里的名字层。名字指向哪里，用户就从哪里进入系统。</p>',31)])])}const h=e(c,[["render",r]]);export{n as __pageData,h as default};
